SELECT u.id,s.id,'Spécialiste en pneumologie pédiatrique, 12 ans expérience. Expert asthme infantile et pathologies respiratoires chroniques.','Dim-Jeu 08h-16h',TRUE,'Oran','','31-MED-0041'
