INSERT INTO consultations_traitement (consultation_id,medicament,dose,duree,instructions) SELECT c.id,'Paracétamol 250mg sirop','3x/jour si fièvre','5 jours','Max 60mg/kg/jour. Donner avec eau. Ne pas dépasser la dose prescrite.' FROM consultations_consultation c JOIN consultations_appointment a ON c.appointment_id=a.id JOIN users_patients p ON a.patient_id=p.id AND p.first_name='Mohamed' AND p.last_name='Dif' AND a.date_rdv::date='2026-04-28';
